import{getRewardPerks,PERKS_COMPLETE}from"./roguelike-system.js";const $=id=>document.getElementById(id);const sleep=ms=>new Promise(r=>setTimeout(r,ms));export function initRewardScreen(){if(!$("reward-screen")){createRewardScreenHTML()}}function createRewardScreenHTML(){const body=document.body;const screen=document.createElement("div");screen.id="reward-screen";screen.className="screen";screen.innerHTML=`\n    <div class="screen-content">\n      <h1 style="text-align: center; margin-bottom: 30px;">🎉 ¡VICTORIA!</h1>\n      \n      <div class="reward-info" style="text-align: center; margin-bottom: 20px; color: #d0f7eb;"></div>\n      \n      <div style="text-align: center; margin-bottom: 20px;">\n        <p style="font-size: 1.2rem; color: #4ecdc4;">Selecciona 1 mejora para tu próximo combate:</p>\n      </div>\n      \n      <div id="reward-perks-container" style="\n        display: grid;\n        grid-template-columns: repeat(3, 1fr);\n        gap: 15px;\n        margin: 30px 0;\n        justify-items: center;\n      "></div>\n      \n      <div id="reward-continue-container" style="\n        text-align: center;\n        margin-top: 30px;\n      "></div>\n    </div>\n  `;body.appendChild(screen);addRewardScreenCSS()}function addRewardScreenCSS(){if(document.getElementById("reward-screen-styles"))return;const style=document.createElement("style");style.id="reward-screen-styles";style.textContent=`\n    #reward-perks-container {\n      padding: 20px;\n      display: grid;\n      grid-template-columns: repeat(3, minmax(180px, 1fr));\n      gap: 18px;\n      width: min(100%, 980px);\n      margin: 0 auto;\n    }\n\n    @media (max-width: 840px) {\n      #reward-perks-container {\n        grid-template-columns: 1fr;\n        gap: 14px;\n      }\n    }\n\n    .reward-perk {\n      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n      border: 2px solid #fff;\n      border-radius: 12px;\n      padding: 20px;\n      cursor: pointer;\n      transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);\n      text-align: center;\n      min-width: 180px;\n      box-shadow: 0 4px 15px rgba(0,0,0,0.2);\n    }\n\n    .reward-perk:hover {\n      transform: translateY(-8px);\n      box-shadow: 0 8px 25px rgba(102, 126, 234, 0.4);\n      border-color: #ffd700;\n    }\n\n    .reward-perk-icon {\n      font-size: 3rem;\n      margin-bottom: 10px;\n    }\n\n    .reward-perk-name {\n      font-weight: bold;\n      font-size: 1.1rem;\n      margin-bottom: 8px;\n      color: #fff;\n    }\n\n    .reward-perk-rarity {\n      font-size: 0.8rem;\n      margin-bottom: 8px;\n      opacity: 0.9;\n      text-transform: uppercase;\n      letter-spacing: 1px;\n    }\n\n    .reward-perk-rarity.common { color: #aaa; }\n    .reward-perk-rarity.uncommon { color: #4ecdc4; }\n    .reward-perk-rarity.rare { color: #9d4edd; }\n    .reward-perk-rarity.epic { color: #ffd700; }\n    .reward-perk-rarity.legendary { color: #ff6348; }\n\n    .reward-perk-description {\n      font-size: 0.9rem;\n      color: #e0e0e0;\n      line-height: 1.4;\n      min-height: 40px;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n    }\n\n    .reward-perk.selected {\n      border-color: #ffd700;\n      box-shadow: 0 0 20px rgba(255, 215, 0, 0.6);\n      background: linear-gradient(135deg, #ff6348 0%, #e74c3c 100%);\n    }\n\n    .reward-continue-btn {\n      background: linear-gradient(135deg, #4ecdc4 0%, #44a08d 100%);\n      color: white;\n      border: none;\n      padding: 15px 40px;\n      font-size: 1.1rem;\n      border-radius: 8px;\n      cursor: pointer;\n      transition: all 0.3s;\n      box-shadow: 0 4px 15px rgba(78, 205, 196, 0.3);\n    }\n\n    .reward-continue-btn:hover:not(:disabled) {\n      transform: scale(1.05);\n      box-shadow: 0 6px 20px rgba(78, 205, 196, 0.5);\n    }\n\n    .reward-continue-btn:disabled {\n      opacity: 0.5;\n      cursor: not-allowed;\n    }\n\n    .reward-info {\n      text-align: center;\n      margin-bottom: 20px;\n      color: #95e1d3;\n      font-size: 0.95rem;\n    }\n  `;document.head.appendChild(style)}export async function showRewardScreen(run,stats){const screen=$("reward-screen");if(!screen){initRewardScreen();return showRewardScreen(run,stats)}const rewards=getRewardPerks(run,3);const runStats=run.getStats();if(rewards.length===0){const emptyMessage=document.createElement("div");emptyMessage.style.color="#ffcc80";emptyMessage.style.fontSize="1rem";emptyMessage.style.padding="24px";emptyMessage.style.background="rgba(255,255,255,0.05)";emptyMessage.style.borderRadius="10px";emptyMessage.style.textAlign="center";emptyMessage.textContent="No hay mejoras nuevas disponibles. Sigue la batalla con las habilidades actuales.";const container=$("reward-perks-container");container.innerHTML="";container.appendChild(emptyMessage)}const infoDiv=screen.querySelector(".reward-info");if(infoDiv){infoDiv.innerHTML=`\n      <p>Racha: <strong>${runStats.wins} victorias</strong> | Perks: <strong>${runStats.perksCount}</strong></p>\n      <p>Dificultad: <strong>${run.difficulty}</strong> | Puntuación total: <strong>${run.totalScore.toLocaleString()}</strong></p>\n    `}const container=$("reward-perks-container");container.innerHTML="";document.querySelectorAll(".screen").forEach(el=>el.classList.remove("active"));screen.classList.add("active");let selectedPerk=null;rewards.forEach((perk,index)=>{const card=document.createElement("div");card.className="reward-perk";card.style.animationDelay=`${index*.1}s`;card.innerHTML=`\n      <div class="reward-perk-icon">${perk.icon}</div>\n      <div class="reward-perk-name">${perk.name}</div>\n      <div class="reward-perk-rarity ${perk.rarity}">${perk.rarity}</div>\n      <div class="reward-perk-description">${perk.description}</div>\n    `;card.addEventListener("click",()=>{document.querySelectorAll(".reward-perk").forEach(c=>c.classList.remove("selected"));card.classList.add("selected");selectedPerk=perk.id});container.appendChild(card)});const continueContainer=screen.querySelector("#reward-continue-container");continueContainer.innerHTML=`\n    <button class="reward-continue-btn" id="reward-continue-btn" disabled>\n      Selecciona una mejora para continuar...\n    </button>\n  `;const continueBtn=$("reward-continue-btn");return new Promise(resolve=>{continueBtn.disabled=true;continueBtn.onclick=async()=>{if(rewards.length===0){continueBtn.textContent="Siguiendo...";continueBtn.disabled=true;continueBtn.onclick=null;await sleep(600);resolve(null);return}if(!selectedPerk)return;run.selectPerk(selectedPerk);continueBtn.textContent="Siguiendo...";continueBtn.disabled=true;continueBtn.onclick=null;await sleep(600);resolve(selectedPerk)};if(rewards.length===0){continueBtn.disabled=false;continueBtn.textContent="Continuar al próximo combate"}document.querySelectorAll(".reward-perk").forEach(card=>{card.addEventListener("click",()=>{continueBtn.disabled=false;continueBtn.textContent="✓ Continuar al próximo combate"})});screen.classList.add("active")})}export function hideRewardScreen(){const screen=$("reward-screen");if(screen){screen.classList.remove("active")}}export function showPerksSummary(run){const stats=run.getStats();if(stats.perksCount===0){return{message:"Aún no tienes perks. ¡Gana tu primer combate!"}}const perksList=stats.perks.map(p=>`  • ${p.icon} ${p.name} (${p.rarity})`).join("\n");return{title:`Perks Recolectados (${stats.perksCount})`,perks:perksList,totalScore:stats.totalScore,wins:stats.wins}}export function showRunSummary(run){const stats=run.getStats();const duration=Math.floor(stats.duration/1e3);const minutes=Math.floor(duration/60);const seconds=duration%60;return{playerName:stats.playerName,playerClass:stats.playerClass,difficulty:stats.difficulty,wins:stats.wins,losses:stats.losses,totalScore:stats.totalScore,perksCount:stats.perksCount,durationText:`${minutes}:${String(seconds).padStart(2,"0")}`,perks:stats.perks.map(p=>p.name)}}